oldWay:
/* Custom checkbox — hides native, rebuilds with pseudo-elements */
input[type='checkbox'] {
  appearance: none;
  width: 16px;
  height: 16px;
  border: 2px solid #a855f7;
  border-radius: 3px;
  cursor: pointer;
}
input[type='checkbox']:checked {
  background: #a855f7;
  /* Checkmark drawn with clip-path or SVG background */
}

